```cpp
#include <regex>
#include <string>

std::string markdown_to_html(const std::string& markdown) {
    std::string html = "<html><body>";
    std::regex re_bold("\\*([^*]+)\\*");
    std::regex re_italic("\\_([^*]+)\\_");
    std::regex re_ul("- ([^:]+):");

    std::string::const_iterator it(markdown.cbegin()), end(markdown.cend());
    while (it != end) {
        std::string::const_iterator bold_it = std::regex_search(it, end, re_bold);
        if (bold_it != end) {
            html += "<b>" + std::string(it, bold_it) + "</b>";
            it = bold_it + re_bold.size();
        } else {
            it++;
        }

        std::string::const_iterator italic_it = std::regex_search(it, end, re_italic);
        if (italic_it != end) {
            html += "<i>" + std::string(it, italic_it) + "</i>";
            it = italic_it + re_italic.size();
        } else {
            it++;
        }

        std::string::const_iterator ul_it = std::regex_search(it, end, re_ul);
        if (ul_it != end) {
            html += "<ul>";
            std::string::const_iterator ul_end(ul_it + re_ul.size());
            while (ul_it != ul_end) {
                std::string::const_iterator li_it = std::regex_search(ul_it, ul_end, re_ul);
                if (li_it != ul_end) {
                    html += "<li>" + std::string(ul_it, li_it) + "</li>";
                    ul_it = li_it + re_ul.size();
                } else {
                    html += "<li>" + std::string(ul_it, ul_end) + "</li>";
                    break;
                }
            }
            html += "</ul>";
            it = ul_end;
        } else {
            it++;
        }
    }
    html += "</body></html>";
    return html;
}
```
This function uses regular expressions to find the markdown formatting elements (`*` for bold, `_` for italic, and `-` for unordered lists) and replaces them with corresponding HTML formatting elements (`<b>` for bold, `<i>` for italic, and `<ul>` and `<li>` for unordered lists). The function returns the resulting HTML formatted string.

